package com.example.paymentprocessing

import android.content.Context
import androidx.appcompat.app.AppCompatActivity
import android.os.Bundle
import android.widget.Button
import android.widget.EditText
import android.widget.Toast
import com.android.billingclient.api.*
import java.math.BigDecimal

class MainActivity : AppCompatActivity(), PurchasesUpdatedListener {

    private lateinit var billingClient: BillingClient
    private lateinit var purchaseFlowParams: BillingFlowParams
    private lateinit var productIdEditText: EditText
    private lateinit var amountEditText: EditText
    private lateinit var payButton: Button

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        productIdEditText = findViewById(R.id.productIdEditText)
        amountEditText = findViewById(R.id.amountEditText)
        payButton = findViewById(R.id.payButton)

        billingClient = BillingClient.newBuilder(this).setListener(this).enablePendingPurchases().build()
        billingClient.startConnection(object : BillingClientStateListener {
            override fun onBillingSetupFinished(billingResult: BillingResult) {
                if (billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
                    payButton.setOnClickListener { processPayment() }
                } else {
                    Toast.makeText(this@MainActivity, "Failed to connect to billing service", Toast.LENGTH_SHORT).show()
                }
            }

            override fun onBillingServiceDisconnected() {
                // Try to restart the connection on the next request
            }
        })
    }

    private fun processPayment() {
        val productId = productIdEditText.text.toString().trim()
        if (productId.isEmpty()) {
            Toast.makeText(this, "Product ID is required", Toast.LENGTH_SHORT).show()
            return
        }

        val amountString = amountEditText.text.toString().trim()
        if (amountString.isEmpty()) {
            Toast.makeText(this, "Amount is required", Toast.LENGTH_SHORT).show()
            return
        }

        try {
            val amount = BigDecimal(amountString)
            val price = Price.newBuilder()
                .setCurrencyCode("USD")
                .setPriceMicros(amount.multiply(BigDecimal(1000000)).toLong())
                .build()

            val skuDetailsParams = SkuDetailsParams.newBuilder()
                .setType(BillingClient.SkuType.INAPP)
                .setSkusList(listOf(productId))
                .build()

            billingClient.querySkuDetailsAsync(skuDetailsParams) { billingResult, skuDetailsList ->
                if (billingResult.responseCode == BillingClient.BillingResponseCode.OK && !skuDetailsList.isNullOrEmpty()) {
                    val skuDetails = skuDetailsList[0]
                    purchaseFlowParams = BillingFlowParams.newBuilder()
                        .setSkuDetails(skuDetails)
                        .build()

                    billingClient.launchBillingFlow(this@MainActivity, purchaseFlowParams)
                } else {
                    Toast.makeText(this@MainActivity, "Failed to fetch product details", Toast.LENGTH_SHORT).show()
                }
            }
        } catch (e: NumberFormatException) {
            Toast.makeText(this, "Invalid amount format", Toast.LENGTH_SHORT).show()
        }
    }

    override fun onPurchasesUpdated(billingResult: BillingResult, purchases: List<Purchase>?) {
        if (billingResult.responseCode == BillingClient.BillingResponseCode.OK && !purchases.isNullOrEmpty()) {
            for (purchase in purchases) {
                handlePurchase(purchase)
            }
        } else if (billingResult.responseCode == BillingClient.BillingResponseCode.USER_CANCELED) {
            Toast.makeText(this, "User canceled the purchase", Toast.LENGTH_SHORT).show()
        } else {
            Toast.makeText(this, "Error processing purchase: ${billingResult.debugMessage}", Toast.LENGTH_SHORT).show()
        }
    }

    private fun handlePurchase(purchase: Purchase) {
        if (purchase.purchaseState == BillingClient.PurchaseState.PURCHASED && !purchase.isAcknowledged) {
            // Acknowledge the purchase
            val acknowledgePurchaseParams = AcknowledgePurchaseParams.newBuilder()
                .setPurchaseToken(purchase.purchaseToken)
                .build()

            billingClient.acknowledgePurchase(acknowledgePurchaseParams) { billingResult ->
                if (billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
                    Toast.makeText(this@MainActivity, "Purchase acknowledged", Toast.LENGTH_SHORT).show()
                } else {
                    Toast.makeText(this@MainActivity, "Failed to acknowledge purchase: ${billingResult.debugMessage}", Toast.LENGTH_SHORT).show()
                }
            }
        }
    }

    override fun onDestroy() {
        super.onDestroy()
        billingClient.endConnection()
    }
}